func:
// ╔════════════════════════════════════════════════════════════╗
// ║  KONFIGUROVATELNÉ PARAMETRY - UPRAV HODNOTY N֦E           ║
// ╚════════════════════════════════════════════════════════════╝

const CONFIG = {
    // === TEPLOTY (°C) ===
    TEPLOTA_MAX: 69,        // Maximální teplota bojleru
    TEPLOTA_VYSOKA: 60,     // Vysoká teplota (bاný ohřev)
    TEPLOTA_STREDNI: 58,    // Střední teplota (levná elektřina)
    TEPLOTA_MIN: 20,        // Minimální teplota (vypnuto)
    TEPLOTA_POVINNY_SOLAR: 40, // Teplota v povinných hodinách když zítra velký solár

    // === HYSTEREZE A SPOTŘEBA ===
    HYSTEREZE: 500,         // Hystereze v W (zabraňuje oscilaci)
    SPOTREBA_BOJLER: 2500,  // Spotřeba bojleru v W

    // === CENOVÉ PRAHY ===
    PRICE_LEVEL_LEVNY: 6,   // Level ceny (1-24), kdy je proud levný
    CENA_KWH_LEVNA: 2.6,    // Cena v Kč/kWh, kdy je proud levný

    // === FORECAST ===
    FORECAST_THRESHOLD: 35000  // Práh forecastu v Wh (35kWh)
};

// ╔════════════════════════════════════════════════════════════╗
// ║  ULOŽENÍ DO FLOW PROMĚNNÝCH - NEMĚNIT                      ║
// ╚════════════════════════════════════════════════════════════╝

for (const [key, value] of Object.entries(CONFIG)) {
    flow.set(key, value);
}

msg.payload = {
    status: "Konfigurace uložena",
    config: CONFIG
};

node.status({fill: "green", shape: "dot", text: "Konfigurace uložena"});
//node.warn("Bojler konfigurace uložena: " + JSON.stringify(CONFIG));

return msg;

// ========== NAČTENÍ KONFIGURACE Z FLOW PROMĚNNÝCH ==========
const TEPLOTA_MAX = flow.get("TEPLOTA_MAX") || 69;
const TEPLOTA_VYSOKA = flow.get("TEPLOTA_VYSOKA") || 60;
const TEPLOTA_STREDNI = flow.get("TEPLOTA_STREDNI") || 55;
const TEPLOTA_MIN = flow.get("TEPLOTA_MIN") || 20;
const TEPLOTA_POVINNY_SOLAR = flow.get("TEPLOTA_POVINNY_SOLAR") || 40;
const HYSTEREZE = flow.get("HYSTEREZE") || 500;
const SPOTREBA_BOJLER = flow.get("SPOTREBA_BOJLER") || 2500;
const PRICE_LEVEL_LEVNY = flow.get("PRICE_LEVEL_LEVNY") || 3;
const CENA_KWH_LEVNA = flow.get("CENA_KWH_LEVNA") || 2.6;
const FORECAST_THRESHOLD = flow.get("FORECAST_THRESHOLD") || 35000;

// ========== NAČTENÍ GLOBÁLNÍCH PROMĚNNÝCH ==========
const max_spotreba_sit = global.get("max_spotreba_sit") || 24000;
const forecast_vyroba_dnes = global.get("forecast_vyroba_dnes") || 0;
const forecast_vyroba_zitra = global.get("forecast_vyroba_zitra") || 0;
const cerpadlo_topi = global.get("cerpadlo_topi") === true;

// v18.9: Aktuální nastavená teplota termostatu (Meross) - guard proti zbytečným zápisům
const climateEntity = global.get("homeassistant.homeAssistant.states['climate.smart_socket_thermostat_24090276694597600801c4e7ae0a2e53']") || {};
const aktualni_nastavena_teplota = parseFloat((climateEntity.attributes || {}).temperature) || 0;

// ========== NAČTENÍ VSTUPNÍCH HODNOT Z MSG ==========
const jsme_doma = msg.jsme_doma === "on";
const rychle_voda = msg.rychle_voda === "on";
const teplota_bojleru = msg.teplota_bojleru || 0;
const spotreba_bojleru_aktualni = msg.spotreba_bojleru || 0;
const battery = msg.battery_percent || 0;
const rozdil_vyroby = msg.rozdil_vyroby || 0;
const letni_rezim = msg.letni_rezim === "on";
const auto_hlad = msg.auto_hlad === "on";
const auto_automatizace = msg.auto_automatizace === "on";
const price_level = msg.price_level || 24;
const cena_kwh = msg.cena_kwh || 10;
const celkova_spotreba = msg.celkova_spotreba || 0;
const spotreba_ze_site = msg.spotreba_ze_site || 0;

// ========== ČASOVÁ KONTROLA ==========
const now = new Date();
const hodina = now.getHours();
const minuty = now.getMinutes();
const cas_minuty = hodina * 60 + minuty;
const je_povinny_cas = cas_minuty >= 17 * 60 && cas_minuty <= 19 * 60 + 30;

// ========== DETEKCE STAVU BOJLERU ==========
const bojler_ohriva = spotreba_bojleru_aktualni > 100;

// ========== KONTROLA LIMITU ODBĚRU ZE SÍTĚ ==========
// === OCHRANA PROTI PŘETÍŽENÍ SÍTĚ ===
// Používáme celkovou spotřebu (AC zátěže bez baterie) místo odběru ze sítě
const config_fve = global.get("fve_config") || {};
const MAX_GRID = config_fve.max_spotreba_sit_w || 22000;
const SAFETY_MARGIN = config_fve.safety_margin_w || 2000;
const SAFE_LIMIT = MAX_GRID - SAFETY_MARGIN;
const volna_kapacita_site = SAFE_LIMIT - celkova_spotreba;
const muzeme_zapnout_bojler = bojler_ohriva || (volna_kapacita_site >= SPOTREBA_BOJLER);

// ========== PRAHY S HYSTEREZÍ ==========
const PRAH_ZAPNUTI_MAX = 4000 + SPOTREBA_BOJLER + HYSTEREZE;
const PRAH_VYPNUTI_MAX = 4000;
const PRAH_ZAPNUTI_VYSOKA = SPOTREBA_BOJLER + HYSTEREZE;
const PRAH_VYPNUTI_VYSOKA = -HYSTEREZE;

// ========== POMOCNÉ FUNKCE ==========
const je_levna_elektrina = (price_level <= PRICE_LEVEL_LEVNY) || (cena_kwh <= CENA_KWH_LEVNA);
const slunecny_den = forecast_vyroba_dnes > FORECAST_THRESHOLD;
const slunecny_den_zitra = forecast_vyroba_zitra > FORECAST_THRESHOLD;

let cilova_teplota = TEPLOTA_MIN;
let duvod = "";

// ========== ROZHODOVACÍ LOGIKA ==========

// 1. Nejsme doma - vždy vypnout
if (!jsme_doma) {
    cilova_teplota = TEPLOTA_MIN;
    duvod = "Nejsme doma";
}
// 2. Rychle teplá voda - override vše
else if (rychle_voda) {
    cilova_teplota = TEPLOTA_MAX;
    duvod = "Rychle teplá voda (override)";
}
// 3. Povinný čas 17:00-19:30 a voda je studená
else if (je_povinny_cas && teplota_bojleru < 58) {
    if (!muzeme_zapnout_bojler) {
        cilova_teplota = TEPLOTA_MIN;
        duvod = "Povinný čas, ale limit sítě";
    } else if (slunecny_den_zitra && teplota_bojleru >= TEPLOTA_POVINNY_SOLAR) {
        // Zítra velký solár a bojler už má 40°C → čekej na solár
        cilova_teplota = TEPLOTA_POVINNY_SOLAR;
        duvod = "Povinný čas, zítra solár " + Math.round(forecast_vyroba_zitra/1000) + "kWh → jen " + TEPLOTA_POVINNY_SOLAR + "°C";
    } else if (slunecny_den_zitra && teplota_bojleru < TEPLOTA_POVINNY_SOLAR) {
        // Zítra velký solár, ale bojler je pod 40°C → natop alespoň na 40°C
        cilova_teplota = TEPLOTA_POVINNY_SOLAR;
        duvod = "Povinný ohřev na " + TEPLOTA_POVINNY_SOLAR + "°C (zítra solár " + Math.round(forecast_vyroba_zitra/1000) + "kWh)";
    } else {
        // Zítra malý solár → normální ohřev
        cilova_teplota = TEPLOTA_VYSOKA;
        duvod = "Povinný ohřev 17:00-19:30";
    }
}
// 4. Baterie plné (>96%) - využijeme solární přebytek
else if (cerpadlo_topi && rozdil_vyroby < PRAH_ZAPNUTI_VYSOKA) {
    // NIBE běží a přebytek nestačí na oba → bojler čeká
    cilova_teplota = TEPLOTA_MIN;
    duvod = "NIBE topí, přebytek " + Math.round(rozdil_vyroby/1000) + "kW nestačí";
}
else if (battery > 96) {
    const prah_max = bojler_ohriva ? PRAH_VYPNUTI_MAX : PRAH_ZAPNUTI_MAX;
    const prah_vysoka = bojler_ohriva ? PRAH_VYPNUTI_VYSOKA : PRAH_ZAPNUTI_VYSOKA;

    if (rozdil_vyroby > prah_max) {
        if (auto_hlad && auto_automatizace) {
            cilova_teplota = TEPLOTA_VYSOKA;
            duvod = "Přebytek " + Math.round(rozdil_vyroby/1000) + "kW, ale auto nabíjí";
        } else {
            cilova_teplota = TEPLOTA_MAX;
            duvod = "Baterie plné + přebytek " + Math.round(rozdil_vyroby/1000) + "kW";
        }
    } else if (rozdil_vyroby > prah_vysoka) {
        cilova_teplota = TEPLOTA_VYSOKA;
        duvod = "Přebytek " + Math.round(rozdil_vyroby/1000) + "kW pokryje ohřev";
    } else if (bojler_ohriva && rozdil_vyroby > -SPOTREBA_BOJLER) {
        cilova_teplota = flow.get("posledni_cilova_teplota") || TEPLOTA_MIN;
        duvod = "Hystereze - udržuji " + cilova_teplota + "°C";
    } else {
        if (!letni_rezim && je_levna_elektrina && muzeme_zapnout_bojler) {
            cilova_teplota = TEPLOTA_STREDNI;
            duvod = "Levná elektřina (L" + price_level + ", " + cena_kwh + " Kč)";
        } else if (letni_rezim) {
            cilova_teplota = TEPLOTA_MIN;
            duvod = "Letní režim - čekám na slunce";
        } else {
            cilova_teplota = TEPLOTA_MIN;
            duvod = "Málo přebytku a drahá elektřina";
        }
    }
}
// 5. Baterie nejsou plné
else {
    const prah = bojler_ohriva ? PRAH_VYPNUTI_VYSOKA : PRAH_ZAPNUTI_VYSOKA;
    const prah_max5 = bojler_ohriva ? PRAH_VYPNUTI_MAX : PRAH_ZAPNUTI_MAX;

    if (rozdil_vyroby > prah_max5) {
        cilova_teplota = TEPLOTA_MAX;
        duvod = "Velký přebytek " + Math.round(rozdil_vyroby/1000) + "kW → " + TEPLOTA_MAX + "°C (bat " + battery + "%)";
    } else if (rozdil_vyroby > prah) {
        cilova_teplota = TEPLOTA_VYSOKA;
        duvod = "Přebytek " + Math.round(rozdil_vyroby/1000) + "kW (bat " + battery + "%)";
    } else if (bojler_ohriva && rozdil_vyroby > -SPOTREBA_BOJLER) {
        cilova_teplota = flow.get("posledni_cilova_teplota") || TEPLOTA_MIN;
        duvod = "Hystereze - udržuji " + cilova_teplota + "°C";
    } else if (letni_rezim && slunecny_den) {
        cilova_teplota = TEPLOTA_MIN;
        duvod = "Letní režim + forecast " + Math.round(forecast_vyroba_dnes/1000) + "kWh";
    } else if (!letni_rezim && je_levna_elektrina && muzeme_zapnout_bojler) {
        cilova_teplota = TEPLOTA_STREDNI;
        duvod = "Levná elektřina (L" + price_level + ", " + cena_kwh + " Kč)";
    } else {
        cilova_teplota = TEPLOTA_MIN;
        if (letni_rezim) {
            duvod = "Letní režim - pouze solar";
        } else if (!muzeme_zapnout_bojler) {
            duvod = "Limit sítě";
        } else {
            duvod = "Drahá elektřina";
        }
    }
}

// ========== ULOŽENÍ STAVU ==========
flow.set("posledni_cilova_teplota", cilova_teplota);

// GUARD 1: Meross unavailable → nezašílat nic (zabrání chybám)
const climateState = (climateEntity || {}).state || "unavailable";
if (climateState === "unavailable") {
    node.status({fill: "red", shape: "ring", text: "Meross UNAVAILABLE - přeskákuji"});
    return null;
}

// GUARD 2: neposílat změnu do Merossu pokud se teplota nezměnila
if (cilova_teplota === aktualni_nastavena_teplota) {
    node.status({fill: "blue", shape: "dot", text: cilova_teplota + "/" + aktualni_nastavena_teplota + "°C - BEZ ZMĚNY - " + duvod});
    return null;
}

// ========== VÝSTUP ==========
msg.payload = {
    teplota: cilova_teplota,
    duvod: duvod,
    config: {
        TEPLOTA_MAX, TEPLOTA_VYSOKA, TEPLOTA_STREDNI, TEPLOTA_MIN,
        HYSTEREZE, SPOTREBA_BOJLER, PRICE_LEVEL_LEVNY, CENA_KWH_LEVNA,
        FORECAST_THRESHOLD
    },
    debug: {
        jsme_doma, rychle_voda, teplota_bojleru, spotreba_bojleru_aktualni,
        bojler_ohriva, battery, rozdil_vyroby, letni_rezim, slunecny_den,
        forecast_vyroba_dnes, forecast_vyroba_zitra, slunecny_den_zitra,
        cerpadlo_topi, auto_hlad, auto_automatizace, price_level,
        cena_kwh, je_levna_elektrina, celkova_spotreba, spotreba_ze_site,
        max_spotreba_sit, MAX_GRID, SAFE_LIMIT, celkova_spotreba, volna_kapacita_site, muzeme_zapnout_bojler,
        je_povinny_cas, cas: hodina + ":" + (minuty < 10 ? "0" : "") + minuty
    }
};

// ========== STATUS ==========
let barva = "grey";
if (cilova_teplota >= TEPLOTA_VYSOKA) barva = "green";
else if (cilova_teplota >= TEPLOTA_STREDNI) barva = "yellow";
node.status({fill: barva, shape: bojler_ohriva ? "ring" : "dot", text: cilova_teplota + "°C - " + duvod});

return msg;

// Filtrace bazénu - Rozhodovací logika
// =====================================
// LÉTO - Zapnutí:
//   8:00 + přebytek > 3kW → ON (early start, flag ON)
//   9:00 → ON (normal start, flag OFF)
//   16:00 + auto nemá hlad + (SOC≥85% + přebytek>3kW NEBO SOC≥94%) → ON
// LÉTO - Vypnutí:
//   Early start → OFF v 11:00
//   Normal start → OFF v 12:00
//   18:00 → OFF pokud SOC<85% nebo přebytek<2kW
//   19:00 → OFF (hard deadline)
// ZIMA:
//   02:00 → ON, 03:00 → OFF (1h filtrace)

var filtraceOn = (msg.filtraceState === "on");
var letniRezim = (msg.letniRezim === "on");
var solarSurplus = parseFloat(msg.solarSurplus) || 0;
var batterySoc = parseFloat(msg.batterySoc) || 0;
var autoMaHlad = (msg.autoMaHlad === "on");
var spustenaDrive = (msg.filtraceSpustenaDrive === "on");

// Timezone-safe (Europe/Prague)
var timeParts = new Date().toLocaleTimeString('en-GB', {timeZone: 'Europe/Prague', hour12: false}).split(':');
var hour = parseInt(timeParts[0]);
var min = parseInt(timeParts[1]);

// Prahy
var SOLAR_ON = 3000;      // W přebytek pro zapnutí
var SOLAR_OFF = 2000;     // W přebytek pro vypnutí
var SOC_HIGH = 85;        // % baterie
var SOC_VERY_HIGH = 94;   // % baterie téměř plná

// Časová okna (odpovídají původním time-range-switch)
function inWindow(h1, m1, h2, m2) {
    var nowM = hour * 60 + min;
    return nowM >= (h1 * 60 + m1) && nowM <= (h2 * 60 + m2);
}

var action = "none";
var reason = "";

if (!filtraceOn) {
    // === FILTRACE VYPNUTA - zapnout? ===
    if (letniRezim) {
        if (inWindow(7,59,8,15) && solarSurplus > SOLAR_ON) {
            action = "on_early";
            reason = "8:00 + přebytek " + Math.round(solarSurplus) + "W";
        } else if (inWindow(8,59,9,15)) {
            action = "on_normal";
            reason = "9:00 - povinný start";
        } else if (inWindow(15,59,16,15) && !autoMaHlad) {
            if (batterySoc >= SOC_HIGH && solarSurplus > SOLAR_ON) {
                action = "on";
                reason = "16:00 SOC:" + batterySoc + "% přebytek:" + Math.round(solarSurplus) + "W";
            } else if (batterySoc >= SOC_VERY_HIGH) {
                action = "on";
                reason = "16:00 SOC:" + batterySoc + "% >= " + SOC_VERY_HIGH + "%";
            }
        }
    } else {
        if (inWindow(1,59,2,3)) {
            action = "on";
            reason = "02:00 - zimní filtrace";
        }
    }
} else {
    // === FILTRACE ZAPNUTA - vypnout? ===
    if (letniRezim) {
        if (spustenaDrive && inWindow(10,59,11,15)) {
            action = "off";
            reason = "11:00 - konec filtrace (early)";
        } else if (!spustenaDrive && inWindow(11,59,12,15)) {
            action = "off";
            reason = "12:00 - konec filtrace (normal)";
        }
        if (action === "none") {
            if (inWindow(17,59,18,15)) {
                if (batterySoc < SOC_HIGH) {
                    action = "off";
                    reason = "18:00 SOC:" + batterySoc + "% < " + SOC_HIGH + "%";
                } else if (solarSurplus < SOLAR_OFF) {
                    action = "off";
                    reason = "18:00 přebytek:" + Math.round(solarSurplus) + "W < " + SOLAR_OFF + "W";
                }
            } else if (inWindow(18,59,19,15)) {
                action = "off";
                reason = "19:00 - hard deadline";
            }
        }
    } else {
        if (inWindow(2,59,3,5)) {
            action = "off";
            reason = "03:00 - konec zimní filtrace";
        }
    }
}

// Status
var st = (letniRezim ? "LÉTO" : "ZIMA");
st += " | " + (filtraceOn ? "ON" : "OFF");
st += " | SOC:" + batterySoc + "% | ΔP:" + Math.round(solarSurplus) + "W";
if (spustenaDrive) st += " | EARLY";
if (action !== "none") st += " → " + action + ": " + reason;
var c = {on_early:"blue", on_normal:"blue", on:"blue", off:"yellow", none:"green"};
node.status({fill: c[action] || "green", shape: "dot", text: st});

// Výstupy: [Filtrace ON, Filtrace OFF, Flag ON, Flag OFF]
var out = [null, null, null, null];
if (action === "on_early" || action === "on_normal" || action === "on") {
    out[0] = {payload: action, reason: reason};
}
if (action === "off") {
    out[1] = {payload: "off", reason: reason};
}
if (action === "on_early") {
    out[2] = {payload: "on"};
}
if (action === "on_normal") {
    out[3] = {payload: "off"};
}
return out;

// =============================================================================
// FVE Konfigurace - Výchozí hodnoty
// =============================================================================

const config = {
    // Baterie
    kapacita_baterie_kwh: 28,
    min_soc: 20,
    max_daily_soc: 80,
    amortizace_baterie_czk_kwh: 1.5,
    charge_efficiency: 0.90,       // 10% ztráta při nabíjení
    discharge_efficiency: 0.90,    // 10% ztráta při vybíjení
    charge_rate_kwh: 5,            // rychlost nabíjení ze sítě (kWh/h)
    soc_drop_normal_pct: 5,        // % pokles SOC za hodinu v NORMAL módu
    daily_consumption_kwh: 20,     // odhadovaná denní spotřeba domu (kWh)

    // Síť
    max_feed_in_w: 7600,
    max_spotreba_sit_w: 22000,
    safety_margin_w: 2000,
    charger_max_amper: 16,  // max ampéry wallboxu
    charger_faze: 3,  // počet fází wallboxu
    sit_napeti: 230,  // napětí sítě (V)
    soc_drop_setrit_pct: 1,
    jistic_a: 32,

    // === NABÍJENÍ AUTA ===
    nabijeni_auta_forecast_kwh: 40,     // min forecast výroby (kWh) pro letní solární nabíjení
    nabijeni_auta_min_soc: 95,          // min SOC baterie pro nabíjení ze sítě (%)
    nabijeni_auta_solar_w: 4000,        // min přebytek výroby pro sluneční nabíjení (W)
    nabijeni_auta_cena_prah_vyssi: 4.3, // max cena kWh pro nabíjení ze sítě (Kč) - vyšší práh
    nabijeni_auta_cena_prah_nizsi: 3.0, // max cena kWh pro nabíjení ze sítě (Kč) - nižší práh
    nabijeni_auta_min_soc_slunce: 85,   // min SOC baterie pro povolení solárního nabíjení (%)
    nabijeni_auta_pretizeni_w: 18000,   // práh přetížení sítě při nabíjení auta (W)
    nabijeni_auta_soc_drain_prah: 95,   // SOC práh pro drain mód solárního nabíjení (%)
    nabijeni_auta_soc_drain_w: 1000,    // max odběr z baterie v drain módu při SOC>=95% (W)
        nabijeni_auta_soc_charge_w: 1000,   // rezerva solaru pro nabíjení baterie při SOC<95% (W)

    // FVE
    fve_peak_kwp: 3,
    fve_azimut: 270,
    fve_sklon: 50,

    // Victron MQTT
    victron_id: "c0619ab69c71",
    victron_mqtt_prefix: "victron",

    // Zdroj solární předpovědi: "VICTRON" nebo "OPEN_METEO"
    solar_forecast_source: "OPEN_METEO",

    // Cenové prahy (level 1-10, 1=nejlevnější)
    prah_levna_energie: 4,      // level <= prah = levná energie
    prah_draha_energie: 12,      // level >= prah = drahá energie
    prah_ultra_levna_nakup: 1.0,   // nákupní cena (Kč/kWh) pod kterou platí ultra-levný režim

    // === TOPENÍ DOMU ===
    topeni_min_teplota_nadrze: 34,   // min teplota nádrže pro oběhové čerpadlo (°C)
    topeni_max_teplota_nadrze: 50,
    topeni_teplota_nepritomnost: 21,
    topeni_solar_margin_hours: 2,
    nibe_peak_w: 14000,
    nibe_cooldown_min: 10,  // min doba mezi NIBE přepnutími (minuty)
    topeni_bezpecny_pokles: 0.7,  // hystereze pod target pro NIBE v drahých hodinách (°C)
    topeni_hystereze_chlazeni: 1.0,  // hystereze chlazení nad target (°C)  // bezpečný pokles pod target (°C) — pod tímto topit i v drahých hodinách
