        if (p3on) actions.push("p3_off");
        reason = "Manuální mod: NIBE – bez zásahů do NIBE | indoor=" + indoorTemp.toFixed(1) + "°C";

    } else if (manualMod === "Patrony") {
        // Manuální PATRONY — topit jen z patron, NIBE blokováno
        // NIBE: nezasahovat – uživatel kontroluje
        var tankOk = tankTemp >= MIN_TANK;
        var patronyMohou = batSoc >= MIN_SOC_PAT && !autoHlad && !autoNabiji && tankTemp < MAX_TANK_PAT && (!gridLost || solarPower > 0);
        // Hlavní loop zapíná patrony POUZE pokud actPat === 0.
        // Pokud patrony běží (actPat > 0), 5s smyčka řídí počet fází.
        if (patronyMohou && actPat === 0) {
            if (availPat >= MIN_PRETOK * 3)      { patTarget = 3; }
            else if (availPat >= MIN_PRETOK * 2) { patTarget = 2; }
            else if (availPat >= MIN_PRETOK)     { patTarget = 1; }
        } else if (patronyMohou && actPat > 0) {
            // Patrony běží — 5s smyčka řídí
            patTarget = actPat;
        }
        // patronyMohou === false → hlavní loop vypne fáze
        var p1want = patTarget >= 1;
        var p2want = patTarget >= 2;
        var p3want = patTarget >= 3;
        if (p1want !== p1on) actions.push(p1want ? "p1_on" : "p1_off");
        if (p2want !== p2on) actions.push(p2want ? "p2_on" : "p2_off");
        if (p3want !== p3on) actions.push(p3want ? "p3_on" : "p3_off");
        reason = "Manuální mod: PATRONY | přebytek=" + Math.round(availPat) + "W fáze=" + patTarget;

    } else if (manualMod === "Obehove") {
        // Manualní OBEHOVE – oběhové čerpadlo, NIBE nezasahovat
        // Patrony zastavit
        if (p1on) actions.push("p1_off");
        if (p2on) actions.push("p2_off");
        if (p3on) actions.push("p3_off");
        var tankOk = tankTemp >= MIN_TANK;
        var needsHeat = indoorTemp < effTarget;
        if (tankOk && needsHeat && !obehOn) {
            actions.push("obehove_on");
            reason = "Manuální mod: OBĚHOVÉ — ON";
        } else if ((!tankOk || !needsHeat) && obehOn) {
            actions.push("obehove_off");
            reason = "Manuální mod: OBĚHOVÉ — OFF";
        } else {
            reason = "Manuální mod: OBĚHOVÉ | nádrž=" + tankTemp.toFixed(1) + "°C";
        }
    }

    // Zapiš aktuální manuální mod do global (pro HA input_select update)
    global.set("topeni_mod", manualMod);

} else {
    var forceStart = flow.get("shutdown_done") === true;  // právě zapnuta automatizace
    flow.set("shutdown_done", false);
    // Reset summer flag pokud se změní automatizace
    if (letniRezim) {
        // LETNÍ REŽIM — jednorázové nastavení default stavu, pak jen chlazení
        var summerDone = flow.get("summer_setup_done") || false;
        if (!summerDone) {
            // Jednorázově: NIBE on (pro TUV), oběhové off, patrony off
            if (canOffNibe) actions.push("nibe_on");
            if (obehOn) actions.push("obehove_off");
            if (p1on) actions.push("p1_off");
            if (p2on) actions.push("p2_off");
            if (p3on) actions.push("p3_off");
            flow.set("summer_setup_done", true);
            reason = "Léto — jednorázové nastavení default";
        }

        // Chlazení — běží stále v létě
        if (coolEnabled) {
            if (!coolOn && indoorTemp > effTarget + HYSTEREZE_CHLAZENI) {
                actions.push("cool_on");
                reason = "Chlazení ON (" + indoorTemp.toFixed(1) + ">" + (effTarget+HYSTEREZE_CHLAZENI).toFixed(1) + "°C)";
            } else if (coolOn && indoorTemp < effTarget) {
                actions.push("cool_off");
                reason = "Chlazení OFF (" + indoorTemp.toFixed(1) + "<" + effTarget.toFixed(1) + "°C)";
            } else {
                reason = "Léto | " + indoorTemp.toFixed(1) + "/" + effTarget.toFixed(1) + "°C" + (coolOn ? " | Chlazení" : "");
            }
        } else {
            if (coolOn) actions.push("cool_off");
            reason = "Léto | chlazení vypnuto";
        }
    } else {
        // ZIMNÍ REŽIM
        flow.set("summer_setup_done", false);

        // 1. Bazénový ventil - kontrola
        if (ventilOn) actions.push("ventil_off");

        // 2. Chlazení OFF v zimě
        if (coolOn) actions.push("cool_off");

        // 3. TOPÉNÍ MOD — vzájemná exkluzivita NIBE a patrony
        // MOD_PATRONY → NIBE blokováno. MOD_NIBE → patrony blokovány.
        var topeniModAktivni = flow.get("topeni_mod_active") || "Vypnuto";

        // Podmínky pro topení
        var tankOk = tankTemp >= MIN_TANK;
        var needsHeat = indoorTemp < effTarget;

        // Podmínky pro spuštění patrony (solární přebytek)
        // Ultra levná: relaxace - nižší SOC práh, patrony mohou brát ze sítě, auto neblokuje
        var ultraSocPrah = ultraLevna ? (config.min_soc || 20) : MIN_SOC_PAT;
        // v19.10: Balancing = patrony blokovány (priority: balancing > patrony)
        var patronyMohou = (!balancingActive || balancingSolarDump) && batSoc >= ultraSocPrah && (ultraLevna || balancingSolarDump || (!autoHlad && !autoNabiji)) && tankTemp < MAX_TANK_PAT && (!gridLost || solarPower > 0);
        var patronyActive = false;
        // Hlavní loop zapíná patrony POUZE pokud actPat === 0 (první zapnutí nebo restart).
        // Jakmile patrony jednou běží, 5s smyčka (pat_korekce_func) přebírá řízení počtu fází.
        if (patronyMohou && actPat === 0) {
            // Patrony neběží — konzervativní start: vždy jen 1 fáze, korekce (5s) přidá další
            // Ultra levná: patrony mohou startovat i bez solárního přebytku (grid je levný)
            if (ultraLevna || availPat >= MIN_PRETOK) {
                patTarget = 1; patronyActive = true;
                // Nastav cooldown pro korekci — čekat než se systém stabilizuje po startu
                flow.set("pat_change_cooldown", 6); // 6×5s = 30s
            }
        } else if (patronyMohou && actPat > 0) {
            // Patrony běží — 5s smyčka řídí, hlavní loop jen zaznamená stav
            patTarget = actPat;
            patronyActive = true;
        }
        // patronyMohou === false → hlavní loop vypne fáze (podmínky nesplněny)

        // Přepínání modu — patrony POUZE pokud teplota je blízko cíle + reálná šance na běh
        // Patrony = POSLEDNÍ priorita — přebytky co nemám kam dát (auto, NIBE, baterie)
        // Velký rozdíl teploty → NIBE (topení domu). Malý rozdíl + reálné patrony → patrony.
        var PATRON_TEMP_MARGIN = 0.3;  // °C — max rozdíl indoor vs target pro patrony
        var tempGap = effTarget - indoorTemp;  // kladné = pod cílem
        // Kontrola reálnosti patrony:
        // 1. SOC musí být blízko MIN_SOC_PAT (max 15% pod) — jinak NIBE topí v levných hodinách
        // 2. Zbývající solar musí pokrýt nabití baterie + spotřebu domu s 50% rezervou
        var patronySocReady = batSoc >= (MIN_SOC_PAT - 15);
        var battNeedWh = Math.max(0, (MIN_SOC_PAT - batSoc) / 100 * kapacitaBat);
        var consumeEstWh = solarHoursLeft * 1500; // ~1.5kWh/h průměrná spotřeba domu
        var patronyRealisticke = ultraLevna || (patronySocReady && zbyvajiciSolar > (battNeedWh + consumeEstWh) * 1.5);
        if (isSolarHour && tempGap <= PATRON_TEMP_MARGIN && needsHeat && patronyRealisticke) {
            // Solární hodiny + teplota blízko cíle + reálná šance na SOC ≥ 95% → mod Patrony
            topeniModAktivni = "Patrony";
        } else if (tempGap > PATRON_TEMP_MARGIN && needsHeat) {
            // Velký rozdíl — dům potřebuje topit přes NIBE
            topeniModAktivni = "NIBE";
        } else if (!needsHeat && patronyActive) {
            // Teplota dosažena + patrony běží → patrony dál ohřívají nádrž
            topeniModAktivni = "Patrony";
        } else if (!needsHeat) {
            topeniModAktivni = "Vypnuto";
        } else {
            // Fallback: needsHeat + ne solární hodiny → NIBE
            topeniModAktivni = "NIBE";
        }
        flow.set("topeni_mod_active", topeniModAktivni);

        // Blokace dle modu
        var nibeBlockedByMod     = (topeniModAktivni === "Patrony");
        var patronyBlockedByMod  = (topeniModAktivni === "NIBE");

        // Patrony ON/OFF (blokované pokud MOD_NIBE)
        // Pokud patrony už běží (actPat > 0), fáze řídí korekce (5s) — hlavní loop jen startuje/stopuje
        var korekceRidi = actPat > 0 && patronyMohou;
        var p1want = !patronyBlockedByMod && patTarget >= 1;
        var p2want = !patronyBlockedByMod && patTarget >= 2;
        var p3want = !patronyBlockedByMod && patTarget >= 3;
        if (!korekceRidi) {
            if (p1want !== p1on) actions.push(p1want ? "p1_on" : "p1_off");
            if (p2want !== p2on) actions.push(p2want ? "p2_on" : "p2_off");
            if (p3want !== p3on) actions.push(p3want ? "p3_on" : "p3_off");
        }

        // 4. NIBE řízení v2.3 — NIBE topí NÁDRŽ, oběhové čerpadlo topí DŮM z nádrže
        //    NIBE se NESMÍ spustit/pokračovat v drahých hodinách (výjimka: velký solár)
        //    V levných hodinách: proaktivně topit nádrž i když dům je OK
        var safeTemp = effTarget - BEZPECNY_POKLES;
        // v19.4: Allow deferral to cheaper hour when temp is above safe minimum
        var canDeferHeat = indoorTemp >= safeTemp;
        var nibeBlockedByPatrony = nibeBlockedByMod;
        var nibeBlockDischarge = true;
        var gridAllowNibe = !gridLost || (gridLost && solarPower >= NIBE_PEAK_W);
        var cheaperAhead = hasCheaperHourAhead(prices, hour, lvl);
        var SOLAR_OVERRIDE_W = config.topeni_solar_override_w || 8000;
        // Proaktivní topení: v levné hodině topit nádrž i když dům nepotřebuje (nádrž < MAX_TANK)
        var tankNeedsHeat = tankTemp < MAX_TANK;
        var nibeWanted = needsHeat || (!isDraha && tankNeedsHeat);

        // === PRIORITA: TOPENÍ > AUTO NABÍJENÍ ===
        if (!ultraLevna && autoNabiji && nibeWanted && !nibeBlockedByPatrony) {
            actions.push("stop_auto_nabijeni");
        }

        // === BEZPEČNOSTNÍ KONTROLY (vždy první) ===
        if (!gridAllowNibe) {
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        } else if (fireplace) {
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        } else if (tankTemp > MAX_TANK) {
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        } else if (nibeBlockedByPatrony) {
            if (nibeOn && canOffNibe) actions.push("nibe_off");

        // === DRAHÁ HODINA → NIBE OFF (jediná výjimka: velký solár) ===
        } else if (isDraha) {
            if (prebytek >= SOLAR_OVERRIDE_W) {
                // Velký solární přebytek → NIBE ON/pokračovat (free energy)
                if (!nibeOn) actions.push("nibe_on");
                nibeBlockDischarge = false;
            } else {
                // Drahá hodina bez soláru → NIBE OFF, NESPOUŠTĚT
                if (nibeOn && canOffNibe) actions.push("nibe_off");
            }

        // === LEVNÁ/STŘEDNÍ HODINA ===
        } else if (nibeWanted) {
            // Levná hodina + (dům potřebuje topit NEBO nádrž pod MAX_TANK)
            // v19.3: Plan setrit = plan už rozhodl že hodina je levná → skip cheaperAhead/bigSolar pro nádrž
            // v19.4: Skip cheaperAhead ONLY when hour is genuinely cheap (lvl ≤ PRAH_LEVNA)
        // Prevents heating at level 5 when level 2 is next hour
        var PRAH_LEVNA = config.prah_levna_energie || 4;
        var planSaysChap = (planCurrentMode === "setrit") && (lvl <= PRAH_LEVNA);
            if (!planSaysChap && !isSolarHour && bigSolarTomorrow && (!needsHeat || canDeferHeat)) {
                // Velký solar zítra + dům nepotřebuje → šetříme pro solár
                if (nibeOn && canOffNibe) actions.push("nibe_off");
            } else if (!planSaysChap && !isSolarHour && cheaperAhead && (!needsHeat || canDeferHeat)) {
                // Levnější hodiny existují + dům nepotřebuje → počkat
                if (nibeOn && canOffNibe) actions.push("nibe_off");
            } else if (prebytek >= SOLAR_OVERRIDE_W) {
                // Velký solární přebytek → NIBE ON bez blokace vybíjení
                if (!nibeOn) actions.push("nibe_on");
                nibeBlockDischarge = false;
            } else {
                // Levná hodina → NIBE ON, topit nádrž
                if (!nibeOn) actions.push("nibe_on");
                nibeBlockDischarge = (batSoc <= 90);
            }

        // === DŮM NEPOTŘEBUJE + NÁDRŽ OK ===
        } else {
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        }

        // Uložit info o blokaci vybíjení pro NIBE
        flow.set("nibe_block_discharge", nibeBlockDischarge);

        // 5. Oběhové čerpadlo (při krbu NESAHAT - řídí jiná automatika)
        // Oběhové je nezávislé na NIBE — čerpá teplo z nádrže do domu kdykoli nádrž má co dát
        // bigSolarTomorrow omezení se týká jen NIBE, ne oběhového (oběhové spotřebuje minimum)
        if (!fireplace) {
            // Noční snížení: oběhové nespouštět pokud teplota neklesla pod targetTemp - NOCNI_SNIZ
            var obehoveTarget = isNight ? (targetTemp - NOCNI_SNIZ) : effTarget;
            var needsHeatObehove = indoorTemp < obehoveTarget;
            // v19.10: Balancing = čerpadlo off (nevybíjet baterii), pokud teplota OK
            if (balancingBlockPump) {
                if (obehOn) actions.push("obehove_off");
            } else if (tankOk && needsHeatObehove) {
                actions.push("obehove_on");
            } else {
                // Nádrž vychladlá nebo teplota v noci OK → čerpadlo off
                if (obehOn) actions.push("obehove_off");
            }
        }

        // Reason
        var parts = [];
        parts.push(isDraha ? "DRAHÁ(Lv" + lvl + ")" : "Lv" + lvl);
        parts.push("In:" + indoorTemp.toFixed(1) + "/" + effTarget.toFixed(1) + "°C");
        parts.push("Tank:" + tankTemp.toFixed(0) + "°C");
        parts.push("DM:" + Math.round(dm));
        parts.push("Out:" + outdoorTemp.toFixed(0) + "°C");
        if (patronyActive) parts.push("PAT:" + patTarget + "f(" + Math.round(availPat) + "W)");
        if (fireplace) parts.push("KRB");
        if (isNight) parts.push("NOC");
        if (ultraLevna) parts.push("ULTRA_LEVNA");
        if (balancingActive) parts.push("⚡BAL");
        if (gridLost) parts.push("⚡GRID_LOST");
        if (isSolarHour) parts.push("☀" + solarHoursLeft + "h");
        if (cheaperAhead) parts.push("LEVNĚJŠÍ↓");
        if (bigSolarTomorrow) parts.push("☀Z:" + Math.round(solarForecastTomorrow) + "kWh");
        parts.push("Safe:" + safeTemp.toFixed(1) + "°C");
        if (!nibeBlockDischarge) parts.push("NoBLK");
        reason = parts.join(" | ");
    }
}

// === OCHRANA: NIBE nelze vypnout pokud pracuje ===
if (actions.indexOf("nibe_off") > -1 && !canOffNibe) {
    actions = actions.filter(function(a) { return a !== "nibe_off"; });
    reason += " ⚠️OCHRANA:NIBE pracuje";
}

// === OCHRANA: nikdy nibe_on + nibe_off zároveň ===
var hasNibeOn = actions.indexOf("nibe_on") > -1;
var hasNibeOff = actions.indexOf("nibe_off") > -1;
if (hasNibeOn && hasNibeOff) {
    // Konflikt — ponechat aktuální stav (nic nedělat)
    actions = actions.filter(function(a) { return a !== "nibe_on" && a !== "nibe_off"; });
    reason += " ⚠️KONFLIKT:on+off→skip";
}

// === COOLDOWN: min doba mezi NIBE přepnutími (přeskočit při forceStart) ===
if ((hasNibeOn && !nibeOn) || (hasNibeOff && nibeOn && canOffNibe)) {
    if (!nibeCooldownOk && !forceStart) {
        actions = actions.filter(function(a) { return a !== "nibe_on" && a !== "nibe_off"; });
        reason += " ⏳COOLDOWN";
    } else {
        flow.set("last_nibe_switch", now);
    }
}

// === FINÁLNÍ BEZPEČNOSTNÍ POJISTKA: NIBE a patrony nikdy současně ===
var hasNibeOnFinal = actions.indexOf("nibe_on") > -1;
var hasPatOnFinal = actions.indexOf("p1_on") > -1 || actions.indexOf("p2_on") > -1 || actions.indexOf("p3_on") > -1;
var patronyRunning = p1on || p2on || p3on;
if (hasNibeOnFinal && (hasPatOnFinal || patronyRunning)) {
    actions = actions.filter(function(a) { return a !== "nibe_on"; });
    reason += " ⚠️MUTEX:NIBE blokováno patronami";
}
if (hasPatOnFinal && nibeOn) {
    actions = actions.filter(function(a) { return a !== "p1_on" && a !== "p2_on" && a !== "p3_on"; });
    reason += " ⚠️MUTEX:patrony blokovány NIBE";
}

// === TOPENÍ MOD: zapsat do global pro HA input_select ===
// topeniModAktivni je undefined pokud automatizace=OFF → použít manualMod nebo "Vypnuto"
var finalTopeniMod = (typeof topeniModAktivni !== "undefined" && topeniModAktivni) ? topeniModAktivni : (global.get("topeni_mod") || "Vypnuto");
global.set("topeni_mod", finalTopeniMod);

// === GLOBAL: cerpadlo_topi pro FVE blokaci ===
var isHeating = pumpState.indexOf("Vytápění") > -1;
var isTUV = pumpState.indexOf("Ohřev vody") > -1 || pumpState.indexOf("TUV") > -1;
// Pokud NIBE běží s velkým solárním ziskem, NEBLOKOVAT vybíjení baterie
var nibeBlkDisch = flow.get("nibe_block_discharge") !== false;  // default true
global.set("cerpadlo_topi", (isHeating || isTUV) && nibeBlkDisch);

// === STATUS ===
var st = [];
st.push(automatizace ? (letniRezim ? "LÉTO" : "ZIMA") : "OFF");
st.push(indoorTemp.toFixed(1) + "/" + effTarget.toFixed(1) + "°C");
st.push("Tank:" + tankTemp.toFixed(0));
st.push("Lv" + lvl);
if (actions.length > 0) st.push("→" + actions.join(","));

var color = "green";
if (!automatizace) color = "grey";
else if (indoorTemp < NOUZ_TEMP) color = "red";
else if (isDraha || patTarget > 0) color = "yellow";
node.status({fill: color, shape: "dot", text: st.join(" | ")});

// === OUTPUT ===
// O1: actions array → router switch
// O2: debug/status
var actionMsgs = null;
if (actions.length > 0) {
    actionMsgs = actions.map(function(a) { return {action: a}; });
}
var statusMsg = {
    payload: {
        automatizace: automatizace, letniRezim: letniRezim,
        indoorTemp: indoorTemp, targetTemp: effTarget,
        tankTemp: tankTemp, dm: dm, outdoorTemp: outdoorTemp,
        priceLevel: lvl, isDraha: isDraha, isNight: isNight,
        nibeOn: nibeOn, obehOn: obehOn, patrony: actPat, patTarget: patTarget,
        fireplace: fireplace, batSoc: batSoc, prebytek: prebytek,
        actions: actions, reason: reason
    }
};
return [actionMsgs, statusMsg];

// Detekce topení vs chlazení — blokace vybíjení baterie
var state = msg.payload || "";
var isHeating = state.indexOf("Vytápění") > -1;
var isTUV = state.indexOf("Ohřev vody") > -1 || state.indexOf("TUV") > -1;
var blockDischarge = isHeating || isTUV;
msg.blockDischarge = blockDischarge;
var txt = blockDischarge
    ? "Blokace (" + (isHeating ? "topení" : "TUV") + ")"
    : "OK - " + state.substring(0, 30);
node.status({fill: blockDischarge ? "yellow" : "green", shape: "dot", text: txt});
return msg;

// Režim nepřítomnosti — snížení teploty když nejsme doma
var config = global.get("fve_config") || {};
var AWAY_TEMP = config.topeni_teplota_nepritomnost || 21;
var letniRezim = config.letni_rezim === true;

function getState(id) {
    var e = global.get("homeassistant.homeAssistant.states['" + id + "']") || {};
    return e.state;
}
function getFloat(id, def) {
    var v = parseFloat(getState(id));
    return isNaN(v) ? (def || 0) : v;
}

var jsme_doma = getState("input_boolean.jsme_doma") === "on";
var currentTemp = getFloat("input_number.nastavena_teplota_v_dome", 22);
var savedTemp = flow.get("away_saved_temp");

if (!jsme_doma && !letniRezim) {
    // Odchod z domu v zimě → snížit teplotu
    if (currentTemp > AWAY_TEMP) {
        // Uložit aktuální teplotu jen pokud jsme ji ještě neuložili
        if (!savedTemp || savedTemp <= AWAY_TEMP) {
            flow.set("away_saved_temp", currentTemp);
        }
        node.status({fill:"yellow", shape:"dot", text:"PRYČ → " + AWAY_TEMP + "°C (uloženo " + currentTemp + "°C)"});
        return {payload: AWAY_TEMP};
    } else {
        node.status({fill:"yellow", shape:"ring", text:"PRYČ | teplota už " + currentTemp + "°C"});
        return null;
    }
} else if (jsme_doma && savedTemp && savedTemp > AWAY_TEMP) {
    // Příchod domů → obnovit uloženou teplotu
    var restoreTemp = savedTemp;
    flow.set("away_saved_temp", null);
    node.status({fill:"green", shape:"dot", text:"DOMA → " + restoreTemp + "°C (obnoveno)"});
    return {payload: restoreTemp};
} else {
    node.status({fill:"grey", shape:"ring", text: jsme_doma ? "DOMA" : (letniRezim ? "LÉTO" : "PRYČ")});
    return null;
}

// Patrony korekce v2.3
// Řídí počet aktivních fází pokud patrony běží (cyklus 5s).
//
// SENZORY:
// sensor.nabijeni_baterii: kladné = baterie se NABÍJÍ, záporné = VYBÍJÍ
// sensor.nabijeni_baterii_minus: kladné = baterie VYBÍJÍ (vždy >= 0)
//
// SOC LOGIKA:
// SOC < 90%: patrony STOP (řeší hlavní loop)
// SOC 90-95%: NO-DRAIN — baterie se NESMÍ vybíjet!
//   - battMinus > 0 → OKAMŽITĚ ubrat fázi
//   - battCharging > 500W (přebytek nabíjí baterii) → po stable přidat fázi
// SOC >= 95%: FORCE-DRAIN — baterie se NESMÍ nabíjet! max_charge_power=0
//   - battCharging > 100 (baterie se stále nabíjí) → přidat fázi agresivně
//   - battMinus > DRAIN_W (1000W) → vybíjí moc → ubrat fázi
//
// OUTPUT 1: [{action},...] → patron router
// OUTPUT 2: {payload: {value: N}} → max_charge_power service

function getState(id) {
    var e = global.get("homeassistant.homeAssistant.states['" + id + "']") || {};
    return e.state;
}
function getFloat(id, def) {
    var v = parseFloat(getState(id));
    return isNaN(v) ? (def || 0) : v;
}
function getBool(id) { return getState(id) === "on"; }
function chargeMsg(value) { return {payload: {value: value}}; }

// === AUTOMATIZACE OFF → MANUÁLNÍ MÓD ===
// Při automatizace=OFF: 1x vypnout všechny fáze, pak absolutně nic nedělat.
// Uživatel ovládá patrony ručně — flow nesmí zasahovat!
var automatizace = getBool("input_boolean.automatizovat_topeni");
if (!automatizace) {
    var p1off = !getBool("switch.patrona_faze_1");
    var p2off = !getBool("switch.patrona_faze_3_2");
    var p3off = !getBool("switch.patrona_faze_3");
    var allOff = p1off && p2off && p3off;
    var alreadyStopped = flow.get("pat_manual_stopped") || false;
    if (!allOff && !alreadyStopped) {
        // Patrony ještě běží → 1x vypnout
        flow.set("pat_manual_stopped", true);
        flow.set("pat_discharge_count", 0);
        flow.set("pat_stable_count", 0);
        flow.set("pat_change_cooldown", 0);
        var stopAll = [];
        if (!p1off) stopAll.push({action: "p1_off"});
        if (!p2off) stopAll.push({action: "p2_off"});
        if (!p3off) stopAll.push({action: "p3_off"});
        node.status({fill:"grey", shape:"ring", text:"MANUAL: 1x STOP všech patrony"});
        return [stopAll, chargeMsg(-1)];
    }
    node.status({fill:"grey", shape:"ring", text:"MANUAL MÓD — flow nezasahuje"});
    return [null, chargeMsg(-1)];
}
// Automatizace ON → reset flagu
flow.set("pat_manual_stopped", false);

function makeActions(current, target, p1, p2, p3) {
    var actions = [];
    if (target > current) {
        if (target >= 1 && !p1) actions.push({action: "p1_on"});
        if (target >= 2 && !p2) actions.push({action: "p2_on"});
        if (target >= 3 && !p3) actions.push({action: "p3_on"});
    } else {
        if (target < 3 && p3) actions.push({action: "p3_off"});
        if (target < 2 && p2) actions.push({action: "p2_off"});
        if (target < 1 && p1) actions.push({action: "p1_off"});
    }
    return actions.length > 0 ? actions : null;
}

// Aktuální stav fází
var p1on = getBool("switch.patrona_faze_1");
var p2on = getBool("switch.patrona_faze_3_2");
var p3on = getBool("switch.patrona_faze_3");
var actPat = (p1on ? 1 : 0) + (p2on ? 1 : 0) + (p3on ? 1 : 0);

var batSoc = getFloat("sensor.battery_percent", 0);
var config = global.get("fve_config") || {};
var DRAIN_SOC_PRAH = config.topeni_patron_drain_soc_prah || 95;
var MIN_SOC_PAT = config.topeni_min_soc_patron || 90;

// max_charge_power: SOC >= 95% → 0 (block), jinak -1 (unlimited)
var chargePower = (batSoc >= DRAIN_SOC_PRAH) ? 0 : -1;
global.set("pat_block_charge", batSoc >= DRAIN_SOC_PRAH);
var chgMsg = chargeMsg(chargePower);

// Žádná fáze neběží → hlavní loop rozhodne
if (actPat === 0) {
    flow.set("pat_discharge_count", 0);
    flow.set("pat_stable_count", 0);
    node.status({fill:"grey", shape:"dot", text:"OFF SOC:" + batSoc + "% chg:" + chargePower});
    return [null, chgMsg];
}

// === PATRONY BĚŽÍ ===
var ultraLevna = global.get("ultra_levna_energie") || false;
var ultraSocPrah = ultraLevna ? (config.min_soc || 20) : MIN_SOC_PAT;

// SOC pod prahem → vypnout VŠECHNY fáze
if (batSoc < ultraSocPrah) {
    var stopActions = [];
    if (p1on) stopActions.push({action: "p1_off"});
    if (p2on) stopActions.push({action: "p2_off"});
    if (p3on) stopActions.push({action: "p3_off"});
    flow.set("pat_discharge_count", 0);
    flow.set("pat_stable_count", 0);
    node.status({fill:"red", shape:"dot", text:"SOC " + batSoc + "% < " + ultraSocPrah + "% → ALL OFF"});
    if (stopActions.length > 0) return [stopActions, chgMsg];
    return [null, chgMsg];
}

// Bateriové senzory
// battMinus: kladné = baterie VYBÍJÍ (sensor.nabijeni_baterii_minus, vždy >= 0)
// battCharging: kladné = baterie se NABÍJÍ, záporné = VYBÍJÍ (sensor.nabijeni_baterii)
var battMinus = getFloat("sensor.nabijeni_baterii_minus", 0);
var battCharging = getFloat("sensor.nabijeni_baterii", 0);

var CHANGE_COOLDOWN = config.topeni_patron_change_cooldown || 6;
var changeCooldown = flow.get("pat_change_cooldown") || 0;

// COOLDOWN — ale při vybíjení v NO-DRAIN zóně reagovat okamžitě
if (changeCooldown > 0) {
    if (batSoc < DRAIN_SOC_PRAH && battMinus > 0 && actPat > 0) {
        // NO-DRAIN zóna + baterie vybíjí → okamžitě ubrat i v cooldownu
        var newT = actPat - 1;
        flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
        flow.set("pat_stable_count", 0);
        node.status({fill:"red", shape:"dot", text:"⚠️NO-DRAIN↓ " + actPat + "→" + newT + "f drain=" + Math.round(battMinus) + "W SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    flow.set("pat_change_cooldown", changeCooldown - 1);
    node.status({fill:"blue", shape:"ring", text:"⏳cd:" + changeCooldown + " " + actPat + "f SOC:" + batSoc + "% chgB:" + Math.round(battCharging) + "W chgP:" + chargePower});
    return [null, chgMsg];
}

// ====================================================================
// SOC 90-95%: NO-DRAIN — baterie se NESMÍ vybíjet
// ====================================================================
if (batSoc >= MIN_SOC_PAT && batSoc < DRAIN_SOC_PRAH) {
    // Baterie vybíjí (battMinus > 0) → OKAMŽITĚ ubrat fázi
    if (battMinus > 0 && actPat > 0) {
        var newT = actPat - 1;
        flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
        flow.set("pat_stable_count", 0);
        node.status({fill:"red", shape:"dot", text:"NO-DRAIN↓ " + actPat + "→" + newT + "f drain=" + Math.round(battMinus) + "W SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    // Baterie se nabíjí hodně (přebytek existuje) → bezpečné přidat fázi
    // battCharging > 500 = baterie se nabíjí 500+W = solární přebytek
    var MIN_SURPLUS = 500;
    var stableCount = flow.get("pat_stable_count") || 0;
    var STABLE_CYCLES = config.topeni_patron_stable_cycles || 6;
    if (battCharging > MIN_SURPLUS && actPat < 3) {
        stableCount++;
        flow.set("pat_stable_count", stableCount);
        if (stableCount >= STABLE_CYCLES) {
            var newT = actPat + 1;
            flow.set("pat_stable_count", 0);
            flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
            node.status({fill:"yellow", shape:"dot", text:"NO-DRAIN↑ " + actPat + "→" + newT + "f surplus=" + Math.round(battCharging) + "W SOC:" + batSoc + "%"});
            return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
        }
        node.status({fill:"green", shape:"dot", text:"NO-DRAIN " + actPat + "f chgB:+" + Math.round(battCharging) + "W (" + stableCount + "/" + STABLE_CYCLES + ") SOC:" + batSoc + "%"});
    } else {
        flow.set("pat_stable_count", 0);
        node.status({fill:"green", shape:"dot", text:"NO-DRAIN " + actPat + "f chgB:" + Math.round(battCharging) + "W SOC:" + batSoc + "%"});
    }
    return [null, chgMsg];
}

// ====================================================================
// SOC >= 95%: FORCE-DRAIN — baterie se NESMÍ nabíjet, max_charge_power=0
// ====================================================================
if (batSoc >= DRAIN_SOC_PRAH) {
    // Baterie se stále nabíjí (battCharging > 100) → přidat fázi agresivně
    if (battCharging > 100 && actPat < 3) {
        var newT = actPat + 1;
        flow.set("pat_change_cooldown", 3);
        flow.set("pat_stable_count", 0);
        node.status({fill:"yellow", shape:"dot", text:"DRAIN↑ " + actPat + "→" + newT + "f chgB:+" + Math.round(battCharging) + "W SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    // Baterie vybíjí příliš (nad DRAIN_W) → ubrat fázi
    var DRAIN_W = config.topeni_patron_drain_w || 1000;
    if (battMinus > DRAIN_W && actPat > 0) {
        var newT = actPat - 1;
        flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
        flow.set("pat_stable_count", 0);
        node.status({fill:"red", shape:"dot", text:"DRAIN↓ " + actPat + "→" + newT + "f drain=" + Math.round(battMinus) + "W>" + DRAIN_W + " SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    node.status({fill:"green", shape:"dot", text:"DRAIN " + actPat + "f chgB:" + Math.round(battCharging) + "W drain=" + Math.round(battMinus) + "W SOC:" + batSoc + "%"});
    return [null, chgMsg];
}

// Fallback
node.status({fill:"grey", shape:"ring", text:"? " + actPat + "f SOC:" + batSoc + "%"});
return [null, chgMsg];

// Sbírka aktuálních dat pro historii (v18: + výroba a spotřeba)
const status = global.get("fve_status") || {};
const config = global.get("fve_config") || {};
const currentPrice = global.get("fve_current_price") || {};
const currentMode = global.get("fve_current_mode") || "normal";

const now = new Date();
const hour = now.getHours();
const dayOfWeek = now.getDay(); // 0 = neděle, 1-6 = po-so
const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
const month = now.getMonth() + 1;

// v18: Aktuální výroba a spotřeba z HA/Victron
// Tyto hodnoty jsou kumulativní za den - potřebujeme delta za hodinu
var solarYieldToday = global.get("fve_vyroba_solar_kwh") || 0;
var gridConsToday = global.get("fve_spotreba_sit_kwh") || 0;
var batteryChargeToday = global.get("fve_nabijeni_bat_kwh") || 0;
var batteryDischargeToday = global.get("fve_vybijeni_bat_kwh") || 0;

// Uložit předchozí hodnoty pro výpočet delta
var prevValues = flow.get("prev_hourly_values") || {};
var prevSolar = prevValues.solar || 0;
var prevGrid = prevValues.grid || 0;
var prevBatCharge = prevValues.batCharge || 0;
var prevBatDischarge = prevValues.batDischarge || 0;

// Delta za poslední hodinu
var hourlySolarKwh = Math.max(0, solarYieldToday - prevSolar);
var hourlyGridKwh = Math.max(0, gridConsToday - prevGrid);
var hourlyBatChargeKwh = Math.max(0, batteryChargeToday - prevBatCharge);
var hourlyBatDischargeKwh = Math.max(0, batteryDischargeToday - prevBatDischarge);

// Celková spotřeba za hodinu = grid + battery_discharge + solar_direct_use
// solar_direct_use ≈ solar_yield - solar_to_battery (přibližně)
// Zjednodušení: spotřeba ≈ grid + battery_discharge (co šlo do domu)
var hourlyConsumptionKwh = hourlyGridKwh + hourlyBatDischargeKwh;

// Solární přebytek = výroba - spotřeba pokrytá solarem
// Přebytek jde do baterie nebo sítě
var hourlySolarSurplusKwh = Math.max(0, hourlySolarKwh - hourlyConsumptionKwh);

// Uložit aktuální hodnoty pro příští hodinu
flow.set("prev_hourly_values", {
    solar: solarYieldToday,
    grid: gridConsToday,
    batCharge: batteryChargeToday,
    batDischarge: batteryDischargeToday,
    hour: hour
});

// Reset na začátku dne (nové kumulativní hodnoty)
if (prevValues.hour !== undefined && hour < prevValues.hour) {
    hourlySolarKwh = 0;
    hourlyGridKwh = 0;
    hourlyConsumptionKwh = 0;
    hourlySolarSurplusKwh = 0;
}

msg.historyData = {
    timestamp: now.toISOString(),
    hour: hour,
    dayOfWeek: dayOfWeek,
    isWeekend: isWeekend,
    month: month,
    soc: status.battery_soc || 0,
    priceLevel: status.price_level || 5,
    priceBuy: currentPrice.buy || 0,
    priceSell: currentPrice.sell || 0,
    mode: currentMode,
    // v18: nová data
    solarKwh: hourlySolarKwh,
    consumptionKwh: hourlyConsumptionKwh,
    solarSurplusKwh: hourlySolarSurplusKwh,
    gridKwh: hourlyGridKwh,
    batChargeKwh: hourlyBatChargeKwh,
    batDischargeKwh: hourlyBatDischargeKwh
};

return msg;

// Uložení dat do historie (v18: + výroba a spotřeba per hodinu)
const data = msg.historyData;
const hour = data.hour;
const dayOfWeek = data.dayOfWeek;
const isWeekend = data.isWeekend;

let history = flow.get("consumption_history") || {};
const dayType = isWeekend ? "weekend" : "weekday";

if (!history[hour]) {
    history[hour] = {};
}

if (!history[hour][dayType]) {
    history[hour][dayType] = {
        count: 0,
        totalSoc: 0,
        avgSoc: 50,
        // v18: výroba a spotřeba
        totalSolarKwh: 0,
        totalConsumptionKwh: 0,
        totalSurplusKwh: 0,
        avgSolarKwh: 0,
        avgConsumptionKwh: 0,
        avgSurplusKwh: 0,
        samples: []
    };
}

const entry = history[hour][dayType];

// Přidat nový vzorek
entry.count++;
entry.totalSoc += data.soc;
entry.avgSoc = Math.round(entry.totalSoc / entry.count);

// v18: akumulovat výrobu a spotřebu
entry.totalSolarKwh = (entry.totalSolarKwh || 0) + (data.solarKwh || 0);
entry.totalConsumptionKwh = (entry.totalConsumptionKwh || 0) + (data.consumptionKwh || 0);
entry.totalSurplusKwh = (entry.totalSurplusKwh || 0) + (data.solarSurplusKwh || 0);

entry.avgSolarKwh = Math.round((entry.totalSolarKwh / entry.count) * 100) / 100;
entry.avgConsumptionKwh = Math.round((entry.totalConsumptionKwh / entry.count) * 100) / 100;
entry.avgSurplusKwh = Math.round((entry.totalSurplusKwh / entry.count) * 100) / 100;

// Uložit posledních 30 vzorků pro analýzu
entry.samples.push({
    timestamp: data.timestamp,
    soc: data.soc,
    priceLevel: data.priceLevel,
    mode: data.mode,
    // v18
    solarKwh: data.solarKwh,
    consumptionKwh: data.consumptionKwh,
    surplusKwh: data.solarSurplusKwh
});

if (entry.samples.length > 30) {
    entry.samples.shift();
}

flow.set("consumption_history", history);

msg.payload = {
    hour: hour,
    dayType: dayType,
    entry: entry,
    message: `Historie aktualizována pro ${hour}:00 (${dayType})`
};

node.status({fill:"green", shape:"dot", text:`${hour}:00 | ${dayType} | cnt:${entry.count} | ☀${entry.avgSolarKwh}kWh | ⚡${entry.avgConsumptionKwh}kWh`});
return msg;

// Výpočet predikce spotřeby a výroby na základě historie (v18)
const history = flow.get("consumption_history") || {};

const now = new Date();
const currentHour = now.getHours();
const dayOfWeek = now.getDay();
const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
const dayType = isWeekend ? "weekend" : "weekday";

const horizont = 12;
const predictions = [];

for (let i = 0; i < horizont; i++) {
    const predictHour = (currentHour + i) % 24;
    const predictDayType = dayType;

    let prediction = {
        hour: predictHour,
        offset: i,
        avgSoc: 50,
        confidence: "low",
        sampleCount: 0,
        // v18: výroba a spotřeba
        avgSolarKwh: 0,
        avgConsumptionKwh: 1.5, // fallback: ~1.5 kWh/h (36 kWh/den / 24h)
        avgSurplusKwh: 0,
        netSolarGainKwh: 0 // přebytek solaru po odečtení spotřeby
    };

    if (history[predictHour] && history[predictHour][predictDayType]) {
        const entry = history[predictHour][predictDayType];
        prediction.avgSoc = entry.avgSoc;
        prediction.sampleCount = entry.count;

        if (entry.count >= 14) {
            prediction.confidence = "high";
        } else if (entry.count >= 7) {
            prediction.confidence = "medium";
        } else {
            prediction.confidence = "low";
        }

        // v18: výroba a spotřeba z historie
        if (entry.avgSolarKwh !== undefined) {
            prediction.avgSolarKwh = entry.avgSolarKwh;
        }
        if (entry.avgConsumptionKwh !== undefined && entry.avgConsumptionKwh > 0) {
            prediction.avgConsumptionKwh = entry.avgConsumptionKwh;
        }
        if (entry.avgSurplusKwh !== undefined) {
            prediction.avgSurplusKwh = entry.avgSurplusKwh;
        }

        // Čistý solární přírůstek pro baterii = výroba - spotřeba
        prediction.netSolarGainKwh = Math.max(0, prediction.avgSolarKwh - prediction.avgConsumptionKwh);
    }

    predictions.push(prediction);
}

msg.payload = {
    currentHour: currentHour,
    dayType: dayType,
    predictions: predictions,
    generatedAt: now.toISOString()
};

global.set("fve_consumption_predictions", predictions);

// Souhrn pro status
var totalSolar = 0, totalCons = 0, totalSurplus = 0;
for (var s = 0; s < predictions.length; s++) {
    totalSolar += predictions[s].avgSolarKwh;
    totalCons += predictions[s].avgConsumptionKwh;
    totalSurplus += predictions[s].netSolarGainKwh;
}

node.status({fill:"blue", shape:"dot", text:`${horizont}h | ☀${totalSolar.toFixed(1)}kWh | ⚡${totalCons.toFixed(1)}kWh | net:${totalSurplus.toFixed(1)}kWh`});

return msg;

// Analýza vzorců spotřeby a výroby pro optimalizaci (v18)
const history = flow.get("consumption_history") || {};

const analysis = {
    weekday: {
        peakHours: [],
        lowHours: [],
        avgPattern: {},
        // v18
        solarPattern: {},
        consumptionPattern: {},
        surplusPattern: {}
    },
    weekend: {
        peakHours: [],
        lowHours: [],
        avgPattern: {},
        solarPattern: {},
        consumptionPattern: {},
        surplusPattern: {}
    },
    recommendations: []
};

for (const dayType of ["weekday", "weekend"]) {
    const hourlyData = [];

    for (let hour = 0; hour < 24; hour++) {
        if (history[hour] && history[hour][dayType]) {
            const entry = history[hour][dayType];
            hourlyData.push({
                hour: hour,
                avgSoc: entry.avgSoc,
                count: entry.count,
                avgSolarKwh: entry.avgSolarKwh || 0,
                avgConsumptionKwh: entry.avgConsumptionKwh || 0,
                avgSurplusKwh: entry.avgSurplusKwh || 0
            });
            analysis[dayType].avgPattern[hour] = entry.avgSoc;
            // v18
            analysis[dayType].solarPattern[hour] = entry.avgSolarKwh || 0;
            analysis[dayType].consumptionPattern[hour] = entry.avgConsumptionKwh || 0;
            analysis[dayType].surplusPattern[hour] = entry.avgSurplusKwh || 0;
        }
    }

    const sorted = [...hourlyData].sort((a, b) => a.avgSoc - b.avgSoc);
    analysis[dayType].peakHours = sorted.slice(0, 3).map(h => h.hour);
    analysis[dayType].lowHours = sorted.slice(-3).map(h => h.hour);
}

if (analysis.weekday.peakHours.length > 0) {
    const peakStr = analysis.weekday.peakHours.join(", ");
    analysis.recommendations.push(`Špičkové hodiny (pracovní dny): ${peakStr}:00 - zvážit nabíjení baterie předem`);
}

if (analysis.weekday.lowHours.length > 0) {
    const lowStr = analysis.weekday.lowHours.join(", ");
    analysis.recommendations.push(`Nízká spotřeba (pracovní dny): ${lowStr}:00 - ideální pro nabíjení ze sítě`);
}

flow.set("consumption_analysis", analysis);
global.set("fve_consumption_analysis", analysis);

msg.payload = analysis;

node.status({fill:"green", shape:"dot", text:`Analýza dokončena | ${analysis.recommendations.length} doporučení`});
return msg;

const history = flow.get("consumption_history") || {};
const analysis = flow.get("consumption_analysis") || {};

msg.payload = JSON.stringify({
    exportedAt: new Date().toISOString(),
    history: history,
    analysis: analysis
}, null, 2);

msg.filename = "fve_history_export.json";

node.status({fill:"blue", shape:"dot", text:"Export připraven"});

return msg;

var patBlockCharge = global.get("pat_block_charge") || false;
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var minSoc = config.min_soc || 20;
var currentSoc = status.battery_soc || 50;
var cerpadloTopi = msg.cerpadloTopi || false;
var autoCharging = msg.autoNabijeniAktivni || false;
// v19.4: Read charger state directly — global may be stale after NR restart
var chargerEntity = global.get("homeassistant.homeAssistant.states['sensor.charger_state_garage']") || {};
if (chargerEntity.state === "2") autoCharging = true;
var saunaAktivni = msg.saunaAktivni || false;
var minDischargeBlokaceW = config.min_vybijeni_blokace_w || 1300;

// v19: Aktualni PV vykon pro rozhodovani o blokaci
var pvFveEntity = global.get("homeassistant.homeAssistant.states['sensor.vyroba_fve']") || {};
var currentPvPower = parseFloat(pvFveEntity.state) || 0;
var dynamicDischargeW = Math.max(0, Math.round(minDischargeBlokaceW - currentPvPower));
// v19.3: Proven pattern from ŠETŘIT — solar<=10W → MaxDischargePower=0
// Eliminates ~130W DC bus standby loss. Victron transfer relay handles grid passthrough.
var solarPassthrough = currentPvPower > 10 ? Math.max(50, Math.round(currentPvPower)) : 0;

// v19: Blokace vybijeni: POUZE pri nabijeni ze site, NIBE bez solaru, nebo saune
var gridChargingEntity = global.get("homeassistant.homeAssistant.states['input_boolean.nastavuj_amperaci_chargeru_grid']") || {};
var autoChargingFromGrid = autoCharging && (gridChargingEntity.state === "on");
var nibeFromGrid = cerpadloTopi;  // NIBE topí → vždy blokovat vybíjení baterie
// v19.4: Hard block discharge when car charges and SOC < threshold (battery priority)
