var stav = global.get("homeassistant.homeAssistant.states['input_number.aktualni_cena_kwh']") || {};
var cena = parseFloat(stav.state);
if (isNaN(cena)) { node.status({fill:'red',shape:'ring',text:'cena NaN'}); return [null, msg]; }
node.status({fill: cena <= prah ? 'green' : 'yellow', shape:'dot', text: cena + ' Kc (prah ' + prah + ')'});
if (cena <= prah) { return [msg, null]; }
return [null, msg];

var config = global.get('fve_config') || {};
var prah = config.nabijeni_auta_pretizeni_w || 18000;
var spotreba = parseFloat(msg.payload);
if (isNaN(spotreba)) { return [null, null]; }
node.status({fill: spotreba > prah ? 'red' : 'green', shape:'dot', text: Math.round(spotreba) + 'W (prah ' + prah + 'W)'});
if (spotreba > prah) { return [msg, null]; }
return [null, msg];

var config = global.get('fve_config') || {};
var prah = config.nabijeni_auta_min_soc_slunce || 85;
var stav = global.get("homeassistant.homeAssistant.states['sensor.battery_percent']") || {};
var soc = parseFloat(stav.state);
if (isNaN(soc)) { node.status({fill:'red',shape:'ring',text:'SOC NaN'}); return [null, msg]; }
node.status({fill: soc > prah ? 'green' : 'yellow', shape:'dot', text: soc + '% (prah ' + prah + '%)'});
if (soc > prah) { return [msg, null]; }
return [null, msg];

let spotreba_sit = msg.payload_spotreba
let battpct = msg.payload_battpct
// Entity 'select.wallboxu_garaz_amperace' vraci '16A' - parsuj cislo
let rawCharger = String(msg.payload_charger || '0');
let chargeramp_a = parseInt(rawCharger.replace(/[^0-9]/g, ''), 10) || 0;
let chargeramp_w = chargeramp_a * 3 * 230;
const config = global.get("fve_config") || {};
let batt_minus = msg.payload_batt_minus || 0;
let rozdil_vyroby_spotreby = msg.payload;

// === PARAMETRY Z CONFIGU ===
let MIN_SOC_SLUNCE = config.nabijeni_auta_min_soc_slunce || 85;
let SOC_DRAIN_THRESHOLD = config.nabijeni_auta_soc_drain_prah || 95;
let SOC_DRAIN_W = config.nabijeni_auta_soc_drain_w || 1000;

// === OCHRANA 1: SOC pod prahem → STOP nabíjení ===
if (battpct < MIN_SOC_SLUNCE) {
    node.status({fill:'red', shape:'ring', text:'SOC ' + battpct + '% < ' + MIN_SOC_SLUNCE + '% → 0A STOP'});
    msg.payload = 0;
    return msg;
}

// === OCHRANA 1b: NIBE MUTEX — čerpadlo topí → auto STOP (v19.4) ===
var cerpadloTopi = global.get("cerpadlo_topi") || false;
if (cerpadloTopi) {
    node.status({fill:'red', shape:'ring', text:'NIBE topí → 0A STOP'});
    msg.payload = 0;
    return msg;
}

// Celkovy dostupny vykon pro wallbox = prebytek + co wallbox uz bere
let availableW = rozdil_vyroby_spotreby + chargeramp_w;
let socZone = '';

// v19.4: Korekční křivka — SOC<95% nabíjí baterii, SOC>=95% vybíjí baterii
let SOC_CHARGE_W = config.nabijeni_auta_soc_charge_w || 1000;
if (battpct >= MIN_SOC_SLUNCE && battpct < SOC_DRAIN_THRESHOLD) {
    // === SOC 85-95%: REZERVUJ solar pro nabíjení baterie ===
    // Snížíme availableW o SOC_CHARGE_W → auto dostane méně, zbytek nabíjí baterii
    availableW -= SOC_CHARGE_W;
    socZone = 'CHARGE-' + SOC_CHARGE_W + 'W';
    // Navíc: pokud se baterie stále vybíjí, odečti i vybíjení
    if (batt_minus > 50) {
        availableW -= batt_minus;
        socZone += ' batt-=' + Math.round(batt_minus) + 'W';
    }
} else if (battpct >= SOC_DRAIN_THRESHOLD) {
    // === SOC >= 95%: baterie se může vybíjet max SOC_DRAIN_W ===
    availableW += SOC_DRAIN_W;
    socZone = 'DRAIN+' + SOC_DRAIN_W + 'W';
}

let targetAmper = Math.floor(availableW / 230 / 3);

// Omezeni rozsahu 0 nebo 6-16A
if (targetAmper > 16) targetAmper = 16;
// v19.4: Keep minimum 6A only if deficit is small (prevents ON/OFF cycling)
// Large deficit (availableW < -1000) → stop immediately, don't keep at 6A
if (targetAmper < 6 && availableW > -1000) {
    targetAmper = 6;  // small deficit — fluctuation, keep running
} else if (targetAmper < 6) {
    targetAmper = 0;  // large deficit — genuinely insufficient solar
}

// DAMPING: max +-2A zmena za cyklus
if (targetAmper > 0 && chargeramp_a >= 6) {
    let diff = targetAmper - chargeramp_a;
    if (diff > 2) targetAmper = chargeramp_a + 2;
    if (diff < -2) targetAmper = chargeramp_a - 2;
    if (targetAmper < 6) targetAmper = 6;
    if (targetAmper > 16) targetAmper = 16;
}

node.status({fill: targetAmper > 0 ? 'green' : 'red', shape: 'dot',
    text: targetAmper + 'A (avail:' + Math.round(availableW) + 'W now:' + chargeramp_a + 'A SOC:' + battpct + '% ' + socZone + ')'});

msg.payload = targetAmper;
