// Čtení aktuálních cen z globální proměnné (bez dotazu do DB)
const prices = global.get("fve_prices_forecast") || [];
const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();

let minuteStart = 0;
if (minute >= 0 && minute < 15) minuteStart = 0;
else if (minute >= 15 && minute < 30) minuteStart = 15;
else if (minute >= 30 && minute < 45) minuteStart = 30;
else minuteStart = 45;

// Find current row
let currentRow = null;
for (const row of prices) {
    if (row.day === "hoursToday" && row.hour === hour && row.minute >= minuteStart && row.minute < minuteStart + 15) {
        currentRow = row;
        break;
    }
}
// Fallback: match just by hour
if (!currentRow) {
    for (const row of prices) {
        if (row.hour === hour) {
            currentRow = row;
            break;
        }
    }
}

if (!currentRow) {
    node.status({fill: "red", shape: "dot", text: "Žádná data pro " + hour + "h"});
    return null;
}

// Find cheapest hours for today
const todayPrices = prices.filter(r => r.day === "hoursToday" || r.day === (currentRow ? currentRow.day : ""));
const hourMap = {};
for (const r of todayPrices) {
    if (!hourMap[r.hour] || r.priceCZKhourBuy < hourMap[r.hour]) {
        hourMap[r.hour] = r.priceCZKhourBuy;
    }
}
const sorted = Object.entries(hourMap).sort((a, b) => a[1] - b[1]);
const cheapestHourBuy = sorted.length > 0 ? parseInt(sorted[0][0]) : 0;
const cheapestSecondHourBuy = sorted.length > 1 ? parseInt(sorted[1][0]) : 0;

const result = {
    priceCZKhourBuy: currentRow.priceCZKhourBuy,
    priceCZKquarterBuy: currentRow.priceCZKquarterBuy,
    priceCZKhourProd: currentRow.priceCZKhourProd,
    priceCZKquarterProd: currentRow.priceCZKquarterProd,
    levelCheapestHourBuy: currentRow.levelCheapestHourBuy,
    levelCheapestQuarterBuy: currentRow.levelCheapestQuarterBuy,
    levelMostExpensiveHourProd: currentRow.levelMostExpensiveHourProd,
    levelMostExpensiveQuarterProd: currentRow.levelMostExpensiveQuarterProd,
    isCheapestHourBuy: currentRow.levelCheapestHourBuy === 1 ? 1 : 0,
    isCheapestSecondHourBuy: currentRow.levelCheapestHourBuy === 2 ? 1 : 0,
    isMostExpensiveHourProd: currentRow.levelMostExpensiveHourProd === 1 ? 1 : 0,
    isMostExpensiveSecondHourProd: currentRow.levelMostExpensiveHourProd === 2 ? 1 : 0,
    isCheapestQuarterBuy: currentRow.levelCheapestQuarterBuy === 1 ? 1 : 0,
    isCheapestSecondQuarterBuy: currentRow.levelCheapestQuarterBuy === 2 ? 1 : 0,
    isMostExpensiveQuarterProd: currentRow.levelMostExpensiveQuarterProd === 1 ? 1 : 0,
    isMostExpensiveSecondQuarterProd: currentRow.levelMostExpensiveQuarterProd === 2 ? 1 : 0,
    cheapestHourBuy: cheapestHourBuy,
    cheapestSecondHourBuy: cheapestSecondHourBuy
};

msg.payload = [result];

// Also update global price level
global.set("fve_current_price", {
    buy: result.priceCZKhourBuy,
    sell: result.priceCZKhourProd,
    levelBuy: result.levelCheapestHourBuy,
    levelSell: result.levelMostExpensiveHourProd
});
global.set("fve_price_level", result.levelCheapestHourBuy);

node.status({fill: result.levelCheapestHourBuy <= 4 ? "green" : (result.levelCheapestHourBuy >= 7 ? "red" : "yellow"), shape: "dot", text: "Level " + result.levelCheapestHourBuy + " @ " + hour + "h | " + prices.length + " rows"});
return msg;

let d = new Date()
let current_minute = d.getMinutes()
let current_hour = d.getHours()
let spusteno_minutou = flow.get("spusteno_minutou")

if ([0, 15, 30, 45].includes(current_minute) && spusteno_minutou != current_minute) {
    flow.set("spusteno_minutou", current_minute)
    return msg;
}

let myCount = flow.get("myCount")
let count = msg.parts.count

if (myCount == count) {
  return msg;
} else flow.set("myCount", ++myCount)

flow.set("myCount", 1)
flow.set("myRecordCount", 0)

return msg;

let myCount = flow.get("myCount")
let myRecordCount = flow.get("myRecordCount")

if (myCount == myRecordCount) {
  msg.payload = "ahoj"
  return msg;
} else flow.set("myCount", ++myCount)

let myCount = flow.get("myCount")
let count = msg.parts.count

if (myCount == count) {
  return msg;
} else flow.set("myCount", ++myCount)

// Po výpočtu levelů: uložit všechny ceny do globální proměnné
const prices = msg.payload || [];
global.set("fve_prices_forecast", prices);

// Find and set current price
const now = new Date();
const hour = now.getHours();
let currentLevel = 5;
for (const row of prices) {
    if (row.hour === hour && row.day === "hoursToday") {
        currentLevel = row.levelCheapestHourBuy || 5;
        global.set("fve_current_price", {
            buy: row.priceCZKhourBuy,
            sell: row.priceCZKhourProd,
            levelBuy: row.levelCheapestHourBuy,
            levelSell: row.levelMostExpensiveHourProd
        });
        break;
    }
}
global.set("fve_price_level", currentLevel);
node.status({fill: "green", shape: "dot", text: prices.length + " cen uloženo do global"});
return msg;
